script:
frappe.ui.form.on('Create Admission', {
    refresh: function(frm) {
        if (frm.doc.application_status === 'Applied' && !frm.is_new()) {
            frm.add_custom_button('Approve', function() {
                frappe.confirm('Are you sure you want to approve this application?', () => {
                    frm.set_value('application_status', 'Approved');
                    frm.save();
                });
            }, 'Actions');

            frm.add_custom_button('Reject', function() {
                frappe.confirm('Are you sure you want to reject this application?', () => {
                    frm.set_value('application_status', 'Rejected');
                    frm.save();
                });
            }, 'Actions');
        }

        if (frm.doc.application_status === 'Approved') {
            frm.dashboard.set_headline_alert('This application is approved and ready for enrollment.', 'green');
        }
        if (frm.doc.application_status === 'Rejected') {
            frm.dashboard.set_headline_alert('This application has been rejected.', 'red');
        }
    }
});
